import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] xi = new int[N];
            int[] Hi = new int[N];
            for (int i = 0; i < N; i++) {
                xi[i] = scanner.nextInt();
                Hi[i] = scanner.nextInt();
            }
            double max = -1;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (Hi[i] < Hi[j]) {
                        double length = Math.sqrt(Math.pow(xi[j] - xi[i], 2) + Math.pow(Hi[j] - Hi[i], 2));
                        double sum = 0;
                        for (int k = 0; k < N; k++) {
                            if (k != i && k != j) {
                                double x = xi[k];
                                double h = Hi[k];
                                double y = (x - xi[i]) * (Hi[j] - Hi[i]) / (xi[j] - xi[i]) + Hi[i];
                                if (h > y) {
                                    sum += h - y;
                                }
                            }
                        }
                        max = Math.max(max, length - sum);
                    }
                }
            }
            System.out.printf("%.6f\n", max);
        }
    }
}

