        x, h = map(int, input().split())
        xi.append(x)
        Hi.append(h)
    max_val = -1
    for i in range(N):
        for j in range(i + 1, N):
            if Hi[i] < Hi[j]:
                length = math.sqrt((xi[j] - xi[i]) ** 2 + (Hi[j] - Hi[i]) ** 2)
                sum_val = 0
                for k in range(N):
                    if k != i and k != j:
                        x = xi[k]
                        h = Hi[k]
                        y = (x - xi[i]) * (Hi[j] - Hi[i]) / (xi[j] - xi[i]) + Hi[i]
                        if h > y:
                            sum_val += h - y
                max_val = max(max_val, length - sum_val)
