const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const xi = [];
    const Hi = [];
    for (let j = 0; j < N; j++) {
        const [x, h] = readline().split(' ').map(Number);
        xi.push(x);
        Hi.push(h);
    }
    let max = -1;
    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            if (Hi[j] < Hi[k]) {
                const length = Math.sqrt(Math.pow(xi[k] - xi[j], 2) + Math.pow(Hi[k] - Hi[j], 2));
                let sum = 0;
                for (let l = 0; l < N; l++) {
                    if (l !== j && l !== k) {
                        const x = xi[l];
                        const h = Hi[l];
                        const y = (x - xi[j]) * (Hi[k] - Hi[j]) / (xi[k] - xi[j]) + Hi[j];
                        if (h > y) {
                            sum += h - y;
                        }
                    }
                }
                max = Math.max(max, length - sum);
            }
        }
    }
    console.log(max.toFixed(6));
}
